import React, { useEffect, useRef, useState, useCallback } from 'react';

import api from '../api';

const MODELS_URL = '/models';

export default function CameraDisplay() {
  const videoRef    = useRef(null);
  const canvasRef   = useRef(null);
  const streamRef   = useRef(null);
  const processingRef = useRef(false);

  const [modelsLoaded, setModelsLoaded]     = useState(false);
  const [modelError,   setModelError]       = useState('');
  const [cameraReady,  setCameraReady]      = useState(false);
  const [windowStatus, setWindowStatus]     = useState(null);
  const [lastResult,   setLastResult]       = useState(null);
  const [recentLogs,   setRecentLogs]       = useState([]);
  const [currentTime,  setCurrentTime]      = useState(new Date());
  const [isFullscreen, setIsFullscreen]     = useState(false);

  // ── Clock ────────────────────────────────────────────────────────
  useEffect(() => {
    const t = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(t);
  }, []);

  // ── Poll attendance window status every minute ────────────────────
  useEffect(() => {
    const fetchStatus = async () => {
      try {
        const res = await api.get('/api/face/status');
        setWindowStatus(res.data);
      } catch {}
    };
    fetchStatus();
    const t = setInterval(fetchStatus, 60000);
    return () => clearInterval(t);
  }, []);

  // ── Load face-api models ──────────────────────────────────────────
  useEffect(() => {
    const loadModels = async () => {
      try {
        await Promise.all([
          faceapi.nets.tinyFaceDetector.loadFromUri(MODELS_URL),
          faceapi.nets.faceLandmark68Net.loadFromUri(MODELS_URL),
          faceapi.nets.faceRecognitionNet.loadFromUri(MODELS_URL),
        ]);
        setModelsLoaded(true);
      } catch (err) {
        setModelError('Failed to load face models. Place model files in /public/models/');
        console.error('Model load error:', err);
      }
    };
    loadModels();
  }, []);

  // ── Start Camera ─────────────────────────────────────────────────
  useEffect(() => {
    if (!modelsLoaded) return;
    const startCamera = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({
          video: { width: 640, height: 480, facingMode: 'user' }
        });
        streamRef.current = stream;
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          videoRef.current.onloadedmetadata = () => {
            videoRef.current.play();
            setCameraReady(true);
          };
        }
      } catch (err) {
        setModelError('Camera not accessible: ' + err.message);
      }
    };
    startCamera();
    return () => {
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
    };
  }, [modelsLoaded]);

  // ── Recognition Loop ─────────────────────────────────────────────
  const recognize = useCallback(async () => {
    if (!cameraReady || !videoRef.current || processingRef.current) return;
    if (!windowStatus?.slot) return; // Only run during attendance windows

    processingRef.current = true;
    try {
      const detection = await faceapi
        .detectSingleFace(videoRef.current, new faceapi.TinyFaceDetectorOptions({ inputSize: 320, scoreThreshold: 0.5 }))
        .withFaceLandmarks()
        .withFaceDescriptor();

      if (!detection) { processingRef.current = false; return; }

      // Draw box on canvas
      if (canvasRef.current && videoRef.current) {
        const dims = { width: videoRef.current.videoWidth, height: videoRef.current.videoHeight };
        faceapi.matchDimensions(canvasRef.current, dims);
        const resized = faceapi.resizeResults(detection, dims);
        const ctx = canvasRef.current.getContext('2d');
        ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
        faceapi.draw.drawDetections(canvasRef.current, resized);
      }

      // Send descriptor to backend
      const descriptor = Array.from(detection.descriptor);
      const res = await api.post('/api/face/recognize', { descriptor });

      if (res.data.success) {
        const log = {
          id: Date.now(),
          name:   res.data.student?.name,
          rollno: res.data.student?.rollno,
          slot:   res.data.slot,
          status: res.data.status,
          time:   new Date().toLocaleTimeString(),
          alreadyMarked: res.data.alreadyMarked,
          confidence: res.data.confidence,
        };
        setLastResult(log);
        if (!res.data.alreadyMarked) {
          setRecentLogs(prev => [log, ...prev.slice(0, 9)]);
        }
      } else {
        setLastResult({ message: res.data.message, success: false });
      }
    } catch (err) {
      console.error('Recognition error:', err.message);
    } finally {
      processingRef.current = false;
    }
  }, [cameraReady, windowStatus]);

  useEffect(() => {
    if (!cameraReady) return;
    const interval = setInterval(recognize, 2000); // run every 2 seconds
    return () => clearInterval(interval);
  }, [cameraReady, recognize]);

  // ── Helpers ───────────────────────────────────────────────────────
  const getWindowBadge = () => {
    if (!windowStatus) return { text: 'Checking...', color: 'bg-slate-700 text-slate-300' };
    if (windowStatus.slot === 'morning') return { text: '🌅 Morning Window Open (9:00–9:30)', color: 'bg-emerald-800 text-emerald-200' };
    if (windowStatus.slot === 'evening') return { text: '🌆 Evening Window Open (4:00–4:30)', color: 'bg-blue-800 text-blue-200' };
    return { text: '⏰ Outside Attendance Window', color: 'bg-slate-700 text-slate-400' };
  };

  const statusBadge = (status) => {
    const map = {
      present:    'bg-emerald-600 text-white',
      'half-day': 'bg-yellow-600 text-white',
      absent:     'bg-red-600 text-white',
    };
    return map[status] || 'bg-slate-600 text-white';
  };

  const badge = getWindowBadge();

  return (
    <div className={`bg-slate-900 text-white min-h-screen flex flex-col ${isFullscreen ? 'fixed inset-0 z-50' : ''}`}>
      {/* Header */}
      <div className="bg-slate-800 border-b border-slate-700 px-6 py-3 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <span className="text-2xl">📷</span>
          <div>
            <div className="font-bold text-base">GNITC Smart Attendance</div>
            <div className="text-slate-400 text-xs">Face Recognition Terminal · CSO 4th Year</div>
          </div>
        </div>
        <div className="flex items-center gap-3">
          <span className={`text-xs px-3 py-1.5 rounded-full font-medium ${badge.color}`}>{badge.text}</span>
          <div className="text-right">
            <div className="text-white font-mono font-bold text-lg leading-tight">
              {currentTime.toLocaleTimeString()}
            </div>
            <div className="text-slate-400 text-xs">{currentTime.toLocaleDateString('en-IN', { weekday:'short', day:'numeric', month:'short' })}</div>
          </div>
          <button onClick={() => setIsFullscreen(!isFullscreen)}
            className="bg-slate-700 hover:bg-slate-600 rounded-lg px-3 py-1 text-sm transition-colors">
            {isFullscreen ? '⊡' : '⛶'}
          </button>
        </div>
      </div>

      <div className="flex flex-1 gap-4 p-4">
        {/* Camera Feed */}
        <div className="flex-1 relative">
          {modelError && (
            <div className="bg-red-900/60 border border-red-700 rounded-xl p-4 mb-4 text-red-300 text-sm">
              ⚠️ {modelError}
            </div>
          )}

          <div className="relative bg-black rounded-2xl overflow-hidden aspect-video w-full border border-slate-700">
            <video ref={videoRef} autoPlay muted playsInline className="w-full h-full object-cover" />
            <canvas ref={canvasRef} className="absolute inset-0 w-full h-full" />

            {!modelsLoaded && !modelError && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/80">
                <div className="text-4xl mb-3 animate-pulse">🤖</div>
                <div className="text-white font-semibold">Loading Face Models...</div>
                <div className="text-slate-400 text-sm mt-1">Please wait</div>
              </div>
            )}
            {modelsLoaded && !cameraReady && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/80">
                <div className="text-4xl mb-3 animate-pulse">📷</div>
                <div className="text-white font-semibold">Starting Camera...</div>
              </div>
            )}

            {/* Live Result Overlay */}
            {lastResult && cameraReady && (
              <div className={`absolute bottom-4 left-1/2 -translate-x-1/2 px-5 py-3 rounded-xl text-center shadow-xl transition-all ${
                lastResult.success ? 'bg-emerald-700/90' : 'bg-slate-800/90 border border-slate-600'
              }`}>
                {lastResult.success ? (
                  <>
                    <div className="text-white font-bold text-lg">{lastResult.alreadyMarked ? '✅' : '🎉'} {lastResult.name}</div>
                    <div className="text-emerald-200 text-sm">{lastResult.rollno} · {lastResult.alreadyMarked ? 'Already marked' : `${lastResult.slot} ✓`}</div>
                    {lastResult.confidence && <div className="text-emerald-300 text-xs mt-0.5">Confidence: {lastResult.confidence}%</div>}
                  </>
                ) : (
                  <div className="text-slate-300 text-sm">{lastResult.message}</div>
                )}
              </div>
            )}
          </div>

          {/* Instructions */}
          {!windowStatus?.slot && (
            <div className="mt-4 bg-slate-800 border border-slate-700 rounded-xl p-4 text-center">
              <div className="text-2xl mb-2">⏰</div>
              <div className="text-white font-semibold">Attendance Windows</div>
              <div className="text-slate-400 text-sm mt-1">Morning: <strong className="text-white">9:00 – 9:30 AM</strong> &nbsp;|&nbsp; Evening: <strong className="text-white">4:00 – 4:30 PM</strong></div>
              <div className="text-slate-500 text-xs mt-1">No attendance on Sundays or Holidays</div>
            </div>
          )}
          {windowStatus?.slot && (
            <div className="mt-4 bg-emerald-900/30 border border-emerald-800 rounded-xl p-4 text-center">
              <div className="text-2xl mb-1">👤</div>
              <div className="text-emerald-300 font-semibold">Stand in front of the camera</div>
              <div className="text-slate-400 text-sm">Your face will be automatically captured</div>
            </div>
          )}
        </div>

        {/* Recent Logs */}
        <div className="w-72 flex flex-col gap-3">
          <div className="bg-slate-800 border border-slate-700 rounded-xl overflow-hidden">
            <div className="px-4 py-3 border-b border-slate-700 flex items-center gap-2">
              <span>📋</span>
              <span className="font-semibold text-sm">Recent Attendance</span>
            </div>
            <div className="divide-y divide-slate-700 max-h-96 overflow-y-auto">
              {recentLogs.length === 0 ? (
                <div className="p-4 text-slate-500 text-sm text-center">No attendance recorded yet</div>
              ) : recentLogs.map(log => (
                <div key={log.id} className="px-4 py-3 animate-fade-in">
                  <div className="flex items-center justify-between gap-2 mb-1">
                    <span className="text-white font-medium text-sm truncate">{log.name}</span>
                    <span className={`text-xs px-2 py-0.5 rounded-full ${statusBadge(log.status)}`}>
                      {log.status}
                    </span>
                  </div>
                  <div className="flex items-center justify-between text-xs text-slate-500">
                    <span>{log.rollno}</span>
                    <span>{log.time}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Status indicators */}
          <div className="bg-slate-800 border border-slate-700 rounded-xl p-4">
            <div className="text-sm font-semibold text-slate-300 mb-3">System Status</div>
            <div className="space-y-2 text-xs">
              <div className="flex items-center justify-between">
                <span className="text-slate-400">Models</span>
                <span className={modelsLoaded ? 'text-emerald-400' : 'text-yellow-400'}>
                  {modelsLoaded ? '✅ Ready' : '⏳ Loading'}
                </span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-slate-400">Camera</span>
                <span className={cameraReady ? 'text-emerald-400' : 'text-red-400'}>
                  {cameraReady ? '✅ Active' : '❌ Offline'}
                </span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-slate-400">Window</span>
                <span className={windowStatus?.slot ? 'text-emerald-400' : 'text-slate-500'}>
                  {windowStatus?.slot ? `✅ ${windowStatus.slot}` : '⏸️ Closed'}
                </span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
